        # Save the received frame for inspection (optional, can remove later)
        cv2.imwrite("received_track_frame.jpg", frame)
        print("Saved received_track_frame.jpg")

        # Check if worker is initialized and an object is being tracked (worker will handle this internally)
        if worker is None:
            return jsonify({"status": "failure", "message": "Predictor worker not initialized."}), 400
        
        # Generate a unique request ID
        request_id = str(uuid.uuid4())
        response_queue = queue.Queue(maxsize=1)
        worker.output_queues[request_id] = response_queue

        # Put task into worker's input queue
        worker.input_queue.put({
            "type": "track",
            "request_id": request_id,
            "frame": frame
        })

        # Wait for response from worker
        result = response_queue.get(timeout=60) # Add a timeout
