if __name__ == "__main__":
    # Initialize the predictor worker before starting the Flask application
    try:
        worker = PredictorWorker(MODEL_CFG, SAM2_CHECKPOINT)
        worker.start() # Start the worker thread
        
        # Listen on all network interfaces, port 5000
        app.run(host="0.0.0.0", port=5000, debug=False)
    except Exception as e:
        print(f"Failed to start Flask service: {e}")
